class EncryptionManager {
    static let shared = EncryptionManager()
    
    // In production, the key should be managed securely, e.g. using Keychain.
    private let symmetricKey: SymmetricKey
    
    private init() {
        // For demonstration, we generate a random key.
        // Replace this with a securely stored key in production.
        self.symmetricKey = SymmetricKey(size: .bits256)
    }
    
    // Encrypt a codable object and return encrypted data.
    func encrypt<T: Codable>(_ object: T) throws -> Data {
        let jsonData = try JSONEncoder().encode(object)
        let sealedBox = try AES.GCM.seal(jsonData, using: symmetricKey)
        // Combining nonce, ciphertext, and tag into one data blob.
        var data = Data()
        data.append(sealedBox.nonce.data)
        data.append(sealedBox.ciphertext)
        data.append(sealedBox.tag)
        return data
    }
    
    // Decrypt the data to the specified codable type.
    func decrypt<T: Codable>(_ data: Data, as type: T.Type) throws -> T {
        // AES.GCM.Nonce uses 12 bytes.
        let nonceSize = 12
        let tagSize = 16
        
        guard data.count >= nonceSize + tagSize else {
            throw NSError(domain: "EncryptionManager", code: -1, userInfo: [NSLocalizedDescriptionKey: "Invalid data"])
        }
        
        let nonceData = data.subdata(in: 0..<nonceSize)
        let tagStartIndex = data.count - tagSize
        let ciphertext = data.subdata(in: nonceSize..<tagStartIndex)
        let tag = data.subdata(in: tagStartIndex..<data.count)
        
        let nonce = try AES.GCM.Nonce(data: nonceData)
        let sealedBox = try AES.GCM.SealedBox(nonce: nonce, ciphertext: ciphertext, tag: tag)
        let decryptedData = try AES.GCM.open(sealedBox, using: symmetricKey)
        return try JSONDecoder().decode(T.self, from: decryptedData)
    }
}

class TransactionManager {
    static let shared = TransactionManager()
    
    private init() { }
    
    // Process a transaction securely by updating the account balance and logging the transaction.
    func processTransaction(for account: inout BankAccount, type: TransactionType, amount: Double) throws {
        // Validate amount
        guard amount > 0 else { return }
        
        // Process transaction securely, ensuring data integrity.
        let transaction = Transaction(id: UUID(), type: type, amount: amount, date: Date())
        
        switch type {
        case .credit:
            account.balance += amount
        case .debit:
            if account.balance >= amount {
                account.balance -= amount
            } else {
                throw NSError(domain: "TransactionManager", code: 100, userInfo: [NSLocalizedDescriptionKey: "Insufficient funds"])
            }
        }
        
        account.transactions.append(transaction)
        
        // Encrypt the transaction record for secure storage.
        _ = try EncryptionManager.shared.encrypt(transaction)
    }
}

class BankingViewController: UIViewController, UITableViewDataSource {
    
