        let button = UIButton(type: .system)
        button.setTitle("Withdraw $50", for: .normal)
        return button
    }()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        view.backgroundColor = .white
        transactionTableView.dataSource = self
        
        view.addSubview(balanceLabel)
