        debitButton.addTarget(self, action: #selector(handleDebit), for: .touchUpInside)
    }
    
    override func viewDidLayoutSubviews() {
        super.viewDidLayoutSubviews()
        let safeArea = view.safeAreaInsets
        balanceLabel.frame = CGRect(x: 20, y: safeArea.top + 20, width: view.frame.width - 40, height: 30)
        creditButton.frame = CGRect(x: 20, y: balanceLabel.frame.maxY + 20, width: view.frame.width/2 - 30, height: 44)
        debitButton.frame = CGRect(x: view.frame.width/2 + 10, y: balanceLabel.frame.maxY + 20, width: view.frame.width/2 - 30, height: 44)
        transactionTableView.frame = CGRect(x: 0, y: debitButton.frame.maxY + 20, width: view.frame.width, height: view.frame.height - debitButton.frame.maxY - 20)
    }
    
    @objc private func handleCredit() {
        do {
            try TransactionManager.shared.processTransaction(for: &bankAccount, type: .credit, amount: 100.0)
            updateUI()
        } catch {
            showAlert(message: error.localizedDescription)
        }
    }
    
    @objc private func handleDebit() {
        do {
            try TransactionManager.shared.processTransaction(for: &bankAccount, type: .debit, amount: 50.0)
            updateUI()
        } catch {
            showAlert(message: error.localizedDescription)
        }
    }
    
    private func updateUI() {
        balanceLabel.text = String(format: "Balance: $%.2f", bankAccount.balance)
        transactionTableView.reloadData()
    }
    
    private func showAlert(message: String) {
        let alert = UIAlertController(title: "Transaction Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
